  /* ------------------------------------------------------------------ */
  /*  Public API                                                        */
  /* ------------------------------------------------------------------ */

  var IC_I18N = {
    LANG_NAMES: LANG_NAMES,
    TRANSLATIONS: TRANSLATIONS,
    currentLang: "en",

    /**
     * Return the translation for `key` in the current language.
     * Falls back to English if the key is missing.
     */
    t: function (key) {
      var lang = TRANSLATIONS[this.currentLang];
      if (lang && lang[key] !== undefined) {
        return lang[key];
      }
      return TRANSLATIONS.en[key] || key;
    },

    /**
     * Switch UI language.
     *  - persists choice in localStorage
     *  - updates the <html lang> attribute
     *  - re-renders every [data-i18n] / [data-i18n-html] element
     *  - updates the page title
     */
    setLanguage: function (lang) {
      if (!TRANSLATIONS[lang]) {
        lang = "en";
      }
      this.currentLang = lang;

      try {
        localStorage.setItem("ic_lang", lang);
      } catch (e) {
        /* private browsing or quota exceeded — ignore */
      }

      document.documentElement.setAttribute("lang", lang);
      this.applyTranslations();
      document.title = this.t("page_title");
    },

    /**
     * Detect the best language to use.
     *  1. Saved preference in localStorage
     *  2. Browser language list (first Indic match wins)
     *  3. Default to English
     */
    detectLanguage: function () {
      var saved;
      try {
        saved = localStorage.getItem("ic_lang");
      } catch (e) {
        saved = null;
      }

      if (saved && TRANSLATIONS[saved]) {
        return saved;
      }

      var indicCodes = ["pa", "hi", "bn", "ta", "te", "kn", "ml", "gu", "or"];
      var browserLangs = (navigator.languages && navigator.languages.length)
        ? navigator.languages
        : (navigator.language ? [navigator.language] : []);

      for (var i = 0; i < browserLangs.length; i++) {
        var code = browserLangs[i].split("-")[0].toLowerCase();
        for (var j = 0; j < indicCodes.length; j++) {
          if (code === indicCodes[j]) {
            return indicCodes[j];
          }
        }
      }

      return "en";
    },

    /**
     * Walk the DOM and apply translations:
     *  - [data-i18n]      → textContent
     *  - [data-i18n-html] → innerHTML
     */
    applyTranslations: function () {
      var self = this;

      var textEls = document.querySelectorAll("[data-i18n]");
      for (var i = 0; i < textEls.length; i++) {
        var key = textEls[i].getAttribute("data-i18n");
        textEls[i].textContent = self.t(key);
      }

      var htmlEls = document.querySelectorAll("[data-i18n-html]");
      for (var j = 0; j < htmlEls.length; j++) {
        var htmlKey = htmlEls[j].getAttribute("data-i18n-html");
        htmlEls[j].innerHTML = self.t(htmlKey);
      }
    }
  };

  window.IC_I18N = IC_I18N;
